// Sanitize the Script field to make it safe for JSON injection
// Removes newlines, carriage returns, tabs, and escapes quotes
const item = $input.item.json;

const rawScript = item.Script || '';

const cleanScript = rawScript
  .replace(/\r\n/g, ' ')  // Windows line endings
  .replace(/\n/g, ' ')    // Unix line endings
  .replace(/\r/g, ' ')    // Old Mac line endings
  .replace(/\t/g, ' ')    // Tabs
  .replace(/\\/g, '\\\\') // Escape backslashes first
  .replace(/"/g, '\\"')   // Escape double quotes
  .replace(/\s+/g, ' ')   // Collapse multiple spaces
  .trim();

return [{
  json: {
    ...item,
    CleanScript: cleanScript
  }
}];
